import{c as e,Q as o,j as r,m as a}from"./chunks/framework.hhGiamYR.js";const i=JSON.parse('{"title":"","description":"","frontmatter":{"date":"2026-06-02T00:00:00.000Z","source":"machiavelli/discourses/book1/01-第一章.md"},"headers":[],"relativePath":"fragments/2026-06-02.md","filePath":"fragments/2026-06-02.md"}'),p={name:"fragments/2026-06-02.md"};function s(_,t,n,u,c,m){return o(),r("div",null,[...t[0]||(t[0]=[a("<p>读了第一章。城邦的起源。李维花了六卷讲的东西，我想用一章说清楚。罗马人把建城当作一项工程——选址、法律、武力——而佛罗伦萨？佛罗伦萨是苏拉的退伍老兵在河边搭了个营地。我们的起点是别人退伍后的闲暇。这个事实比任何政治理论都更能解释佛罗伦萨为什么永远是二流。</p><hr><p>&quot;贫瘠之地使人勤劳，富庶之地使人懒散。&quot;他这么写。但他立刻又说：如果你能用法律取代地理的约束，富庶之地更好——因为你可以扩张。罗马选了富庶，然后用法律制造了贫瘠的纪律。</p><p>我坐在圣卡夏诺的乡下书房里，窗外是托斯卡纳的丘陵。这里既不贫瘠也不富庶——刚好够活，刚好不够做什么大事。也许这就是为什么我在这里写这些。</p><hr><p>他提到亚历山大拒绝在圣山顶上建城。建筑师说可以把城建成人体形状——多么壮丽的构想！亚历山大笑了：&quot;居民吃什么？&quot;</p><p>实效真理。又一次实效真理。宏伟的形式如果不能养活人，那就连粪土都不如。这和《君主论》里说的是一回事：一个君主如果没有实力，所有的美德都是装饰。可是有多少人愿意承认这一点？他们宁愿赞美圣山顶上的人形城市。</p><hr><p>努马、罗慕路斯——他提到这些名字时带着一种我不熟悉的敬意。他相信立法者可以塑造一个民族的性格。但他也说了那句要命的话：&quot;人们的行为或是出于必然，或是出于选择。&quot;大多数人只是在必然里活着。立法者的工作是把必然伪装成选择。</p><p>我在第二秘书厅干了十四年，见过太多&quot;选择&quot;——其实全是被法国人、被教皇、被皇帝逼出来的。</p><hr><p>&quot;令其他城市熠熠生辉的优点，被他们悉数留给了罗马。&quot;最后这句话。是嫉妒，还是自勉？我觉得两者都有。在一个退伍老兵营地上建起来的城市里，写一部能和李维并列的著作——这大概就是我的圣山顶。没有建筑师来问我吃什么。我自己种。</p>",12)])])}const f=e(p,[["render",s]]);export{i as __pageData,f as default};
